my $date = $rows[0][0];
my $author = $rows[1][0];

# Assuming tables start from the second line
my @tables = splice @rows, 1;

# Print the extracted information
print "Date: $date\n";
print "Author: $author\n";

# Dump tables for further processing
print "Tables:\n", Dumper(@tables);

# Save the processed data to a CSV file
my $csv_file = 'extracted_data.csv';
open(my $fh, '>', $csv_file) or die "Could not open file '$csv_file' $!";
